-- あわい屋ZEROS  AI（AI活用）クイズ再設計 seed  2026-06-29
-- 設計: 各動画(b0a10X50)の直後に「動画別クイズ(b0a10X90・3問)」を配置(sort 2,4..18)。
--       コース末に「総合クイズ(b0a1f000・5問)」を配置(sort 99)。動画は sort 1,3..17。
-- 出典: 本文(article_content)準拠。各動画3問は精選＋正解キー照合済み、総合5問は横断新規。
-- 冪等: 動画sort=固定値 / quizレッスン=ON CONFLICT(id) DO UPDATE / 設問=lesson_id単位でDELETE→INSERT。
-- 前提: seed_ai_video_lessons.sql 実行後(動画 b0a10X50 が存在)に流す。
-- 注意: 旧 seed_ai_quiz.sql(各5問・コース末まとめ) はこの設計に置き換え。
-- =====================================================================

-- 1. 動画を奇数sortへ（直後にクイズを挟むため）
UPDATE public.lessons SET sort_order=1 WHERE id='b0a10150-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=3 WHERE id='b0a10250-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=5 WHERE id='b0a10350-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=7 WHERE id='b0a10450-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=9 WHERE id='b0a10550-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=11 WHERE id='b0a10650-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=13 WHERE id='b0a10750-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=15 WHERE id='b0a10850-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=17 WHERE id='b0a10950-0000-4000-8000-000000000000';

-- 2. クイズレッスン upsert（動画別3問=b0a10X90 / 総合5問=b0a1f000）
ON CONFLICT (id) DO UPDATE
  SET course_id=EXCLUDED.course_id, title=EXCLUDED.title, content_type=EXCLUDED.content_type, estimated_minutes=EXCLUDED.estimated_minutes, sort_order=EXCLUDED.sort_order;

-- 3. 既存設問クリア（冪等）
DELETE FROM public.quiz_questions WHERE lesson_id IN (
  'b0a10190-0000-4000-8000-000000000000',
  'b0a10290-0000-4000-8000-000000000000',
  'b0a10390-0000-4000-8000-000000000000',
  'b0a10490-0000-4000-8000-000000000000',
  'b0a10590-0000-4000-8000-000000000000',
  'b0a10690-0000-4000-8000-000000000000',
  'b0a10790-0000-4000-8000-000000000000',
  'b0a10890-0000-4000-8000-000000000000',
  'b0a10990-0000-4000-8000-000000000000',
  'b0a1f000-0000-4000-8000-000000000000'
);

